method SumArray(a: array<int>) returns (s: int)
  ensures s == Sum(a[..], 0, a.Length)
{
  s := 0;
  var i := 0;
  while i < a.Length
    invariant 0 <= i <= a.Length
    invariant s == Sum(a[..], 0, i)
  {
    s := s + a[i];
    i := i + 1;
  }
}

method MaxElement(a: array<int>) returns (m: int)
  requires a.Length > 0
  ensures forall i :: 0 <= i < a.Length ==> a[i] <= m
  ensures exists i :: 0 <= i < a.Length && a[i] == m
{
  m := a[0];
  var i := 1;
  while i < a.Length
    invariant 1 <= i <= a.Length
    invariant forall j :: 0 <= j < i ==> a[j] <= m
    invariant exists j :: 0 <= j < i && a[j] == m
  {
    if a[i] > m { m := a[i]; }
    i := i + 1;
  }
}

method CountOccurrences(a: array<int>, key: int) returns (c: int)
  ensures c == |set i | 0 <= i < a.Length && a[i] == key|
{
  c := 0;
  var i := 0;
  while i < a.Length
    invariant 0 <= i <= a.Length
    invariant c == |set j | 0 <= j < i && a[j] == key|
  {
    if a[i] == key { c := c + 1; }
    i := i + 1;
  }
}

method CopyArray(src: array<int>) returns (dst: array<int>)
  ensures dst.Length == src.Length
  ensures forall i :: 0 <= i < src.Length ==> dst[i] == src[i]
  ensures fresh(dst)
{
  dst := new int[src.Length];
  var i := 0;
  while i < src.Length
    invariant 0 <= i <= src.Length
    invariant forall j :: 0 <= j < i ==> dst[j] == src[j]
  {
    dst[i] := src[i];
    i := i + 1;
  }
}

method TwoSum(a: array<int>, target: int) returns (i: int, j: int)
  requires Sorted(a, 0, a.Length)
  ensures 0 <= i < j < a.Length ==> a[i] + a[j] == target
{
  i, j := 0, a.Length - 1;
  while i < j
    invariant 0 <= i && j < a.Length
    invariant forall p, q :: 0 <= p < i && i <= q < a.Length ==> a[p] + a[q] != target
  {
    if a[i] + a[j] == target { return; }
    else if a[i] + a[j] < target { i := i + 1; }
    else { j := j - 1; }
  }
  return -1, -1;
}

